previewCss:
.darma-loader-darma-custom-425 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  position: relative;
  overflow: hidden;
  border: 2px solid;
}.darma-loader-darma-custom-425::before {content: "";
  position: absolute;
  inset: -48px;
  --c: conic-gradient(from 180deg at 50% calc(100% - 2px),currentColor 90deg, #0000 0);
  background: var(--c),var(--c);
  background-position: 0 0,8px 0;
  background-size: 16px 9.6px;
  animation: darma-loader-darma-custom-425-l16 2s infinite;
}@keyframes darma-loader-darma-custom-425-l16 {50% {background-position: 0 -9.6px ,8px 9.6px;
   transform: rotate(90deg)}100% {background-position: 0 -19.2px,8px 19.2px;
  transform: rotate(180deg)}}

